        size_t end = s.size();
        while (end > 0 && std::isspace(static_cast<unsigned char>(s[end - 1]))) {
            --end;
        }
        s.erase(end);
    };

    trim_start(left);
    trim_end(left);
    trim_start(right);
    trim_end(right);

    return right + "|" + left;
}

